MRFSegmentVentServices::MRFSegmentVentServices():CATBaseUnknown()
{
	_pMRFVentFactory = NULL;
	_piMRFPointVent = NULL;
	_spReferenceVent = NULL_var;
	_spReferenceSurface = NULL_var;

	_U = 0.;
	_V = 0.;
	_DeltaU = 0.;
	_DeltaV = 0.;

	_VentType = 5;
}

//-----------------------------------------------------------------------------
