HRESULT MRFSegmentVentServices::BuildVent(CATIMmiMechanicalFeature_var & iospPointVentFeature)
{
	HRESULT rc = E_FAIL;

	if (NULL == _piMRFPointVent && NULL_var != iospPointVentFeature)
	{
		iospPointVentFeature->QueryInterface(IID_MRFIPointVent, (void**)&_piMRFPointVent);
	}

	if (NULL == _piMRFPointVent && NULL != _pMRFVentFactory)
	{
		rc = _pMRFVentFactory->CreatePointVent(_piMRFPointVent);
	}

	if (NULL != _piMRFPointVent)
	{
		if (5 == _VentType)
		{
			rc = _piMRFPointVent->SetVentType(_VentType);
		}

		if (NULL_var != _spReferenceVent)
		{
			rc = _piMRFPointVent->SetRefVent1(_spReferenceVent);
		}

		CATBaseUnknown_var spOldSurface;
		_piMRFPointVent->GetRefSurface(spOldSurface);
		if (NULL_var != _spReferenceSurface && spOldSurface != _spReferenceSurface)
		{
			rc = _piMRFPointVent->SetRefSurface(_spReferenceSurface);
		}

		double oldU = 0.;
		double oldV = 0.;
		double oldDeltaU = 0.;
		double oldDeltaV = 0.;
		_piMRFPointVent->GetSurfaceParamU(oldU);
		_piMRFPointVent->GetSurfaceParamV(oldV);
		_piMRFPointVent->GetDeltaParamU(oldDeltaU);
		_piMRFPointVent->GetDeltaParamV(oldDeltaV);

		if (oldU != _U)
			rc = _piMRFPointVent->SetSurfaceParamU(_U);
		if (oldV != _V)
			rc = _piMRFPointVent->SetSurfaceParamV(_V);
		if (oldDeltaU != _DeltaU)
			rc = _piMRFPointVent->SetDeltaParamU(_DeltaU);
		if (oldDeltaV != _DeltaV)
			rc = _piMRFPointVent->SetDeltaParamV(_DeltaV);

		if (NULL != _piMRFPointVent)
		{
			_piMRFPointVent->UpdateFeature();
			if (NULL_var == iospPointVentFeature || _piMRFPointVent != iospPointVentFeature)
				iospPointVentFeature = _piMRFPointVent;
			rc = S_OK;
		}
	}
	return rc;
}
